var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"현재 좌표... 식별 불가능//","JPN":"現在座標……識別不可//","ENG":"Current coordinates... unidentifiable//","TWN":"目前座標……無法識別//"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"근방 500km 이내 생명체_ 탐지 되지 않음//","JPN":"半径500km以内の生命体_ 探知結果_未確認//","ENG":"No lifeforms detected within a 500 km radius//","TWN":"方圓500km內未偵測到生命體//"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"빛 감지 되지 않음_ 암흑물질 밀도 매우 높음_//","JPN":"光_未感知_暗黒物質の密度_高_//","ENG":"No light detected_ Dark matter density extremely high_//","TWN":"未偵測到光源_暗物質密度極高//"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"허수공간을 표류 중인 것으로_추정//","JPN":"虚数空間を漂流中と推定//","ENG":"Estimated to be drifting through imaginary space//","TWN":"推測_正在虛數空間漂流//"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"동력_부족... 탈출 방도_없음//","JPN":"動力不足……脱出方法_無し//","ENG":"Power insufficient... No escape method available//","TWN":"動力不足……沒有_逃脫方法//"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"...기능 정지까지 남은 시간 180초.","JPN":"……機能停止まで残り180秒。","ENG":"...Time remaining until system shutdown: 180 seconds.","TWN":"……距離功能停止剩餘時間180秒。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"휴우, 밖에 되게 춥다.","JPN":"ふう、外はすごく寒いなあ。","ENG":"Whew, it's really cold outside.","TWN":"呼，外面好冷。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":null,"R":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"저 찾으셨어요, 대표님?","JPN":"呼びましたか、代表？","ENG":"Were you looking for me, Boss?","TWN":"你找我嗎，代表？"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":null,"R":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"...대시.","JPN":"……ダッシュ。","ENG":"...Dash.","TWN":"……黛西。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"별로 남은 시간이 없어서, 이야기나 나누려고 불렀습니다.","JPN":"残り時間が少ないので、話でもしようかと思って呼びました。","ENG":"There isn't much time left, so I called you to talk for a bit.","TWN":"剩下的時間不多了，所以我想和你聊聊天。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"앗, 그럼 리타 언니도 불러올까요?","JPN":"あっ、じゃあリタお姉ちゃんも呼びましょうか？","ENG":"Oh, then should I bring Rita over too?","TWN":"啊，那要不要也叫麗塔姐姐過來？"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"괜찮습니다.","JPN":"いいえ。","ENG":"That won't be necessary.","TWN":"不用了。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"괜히 불렀다간, 왜 더 잘 하지 못했냐며 잔소리나 들을 것 같군요.","JPN":"呼んだら、なぜもっと上手くできなかったのかと小言を言われそうです。","ENG":"If I call her over for no reason, I feel like she'll just scold me for not doing better.","TWN":"要是叫她來，恐怕又得聽她嘮叨為什麼做得不夠好。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"에이, 그렇지 않아요.","JPN":"ええ～、そんなことありませんよ。","ENG":"Oh, that's not true.","TWN":"唉唷，不會啦。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"대표님은 인류를 지키기 위해 최선을 다하신 걸요. 리타 언니도 분명 잘했다고 할 거에요.","JPN":"代表は人類を守るために最善を尽くしたんですから。リタお姉ちゃんもきっと褒めてくれます。","ENG":"You did your best to protect humanity, Boss. I'm sure Rita would say you did well too.","TWN":"麗塔姐姐一定也會說代表為了守護人類竭盡全力。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"딱히 그런 거창한 사명으로 움직인 건 아니었습니다.","JPN":"別にそういう大袈裟な使命感で動いたわけではありません。","ENG":"I wasn't acting out of any grand mission like that.","TWN":"我並不是為了那麼宏大的使命行動。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제가 타기리온을 만나려 한 건... 두 사람의 복수를 하기 위해서였으니까요.","JPN":"私がタギリオンに会おうとしたのは……二人の復讐をするためでしたから。","ENG":"The reason I tried to meet Thagirion... was to take revenge for the two of you.","TWN":"我想見塔基里翁……只是為了替兩個人報仇而已。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"복수를요? 저희 때문에요?","JPN":"復讐？　私たちのですか？","ENG":"Revenge? Because of us?","TWN":"報仇？因為我們嗎？"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"WILBUR_NPC_NULL_CHANGE1","text":{"KOREA":"알고 있어? 애초에 그 두 녀석이 타기리온이란 괴물한테 찍히는 바람에 일이 꼬인 거야!","JPN":"わかるか？　そもそもあの二人がタギリオンって化け物に狙われたせいでこじれてしまったんだよ！","ENG":"You know something? Things went south in the first place because those two rubbed that monster Thagirion the wrong way!","TWN":"你知道嗎？一開始是那兩個傢伙，被叫什麼塔基里翁的怪物盯上，事情才會搞砸的！"},"stage":{"bg":"HORIZON_05_A","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"관리국에서 말하길, 타기리온은 수많은 세계를 거치며 자신과 똑같은 운명을 자매로 거둬들였다고 하더군요.","JPN":"管理局の話によると、タギリオンは多くの世界を経ながら、自分と同じ運命を持つ者を姉妹として取り込むということでした。","ENG":"According to the Administration, Thagirion passed through countless worlds and gathered sisters who shared the same fate as itself.","TWN":"管理局說塔基里翁穿越無數世界，把與自己相同命運的存在都當作姐妹收集起來。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"정말 운명이란 게 존재한다면, 그자는 대시와 똑같은 운명을 가진 자라는 뜻이겠죠.","JPN":"本当に運命というものが存在するのなら……あの者はダッシュと同じ運命を持つということです。","ENG":"If something like fate really exists, then that means it's someone who shares the same fate as you, Dash.","TWN":"如果真的有命運存在，那她就是與黛西擁有相同命運的人。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그래서 복수를 한 뒤에... 물어보고 싶었습니다.","JPN":"だから復讐を遂げた後……聞きたかったのです。","ENG":"So after taking revenge... I wanted to ask.","TWN":"所以在完成報仇後……我想問她。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"왜 그래야만 했는지.","JPN":"なぜそうしなければならなかったのか。","ENG":"Why it had to be that way.","TWN":"為什麼非得這麼做。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"다른 세상의 자신에게서 행복한 일상을 빼앗는 것에... 대체 무슨 의미가 있는지.","JPN":"別の世界の自分から幸せな日常を奪うことに……いったい何の意味があるのか。","ENG":"What meaning there could possibly be... in taking away the peaceful everyday lives of its other selves in different worlds.","TWN":"從其他世界的自己身上奪走幸福的日常生活……究竟有什麼意義。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"정말 타기리온이 저랑 같은 존재라면...","JPN":"本当にタギリオンが私と同じ存在なら……","ENG":"If Thagirion really is the same kind of being as me...","TWN":"如果塔基里翁真的和我一樣……"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"...그 사람도 분명 그런 일을 하면서 괴로웠을 거라고 생각해요.","JPN":"……その人もきっと、そんなことをしながら辛かったと思います。","ENG":"...Then I think they must have suffered while doing those things too.","TWN":"……那個人在做那些事時一定也會感到痛苦。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그런 일을 당하고도 그 괴물을 이해하려 하다니. 대시는 정말 순진한 휴먼이군요.","JPN":"あんな目に遭ってもあの化け物を理解しようとするとは、ダッシュは本当に純真なヒューマンですね。","ENG":"Trying to understand that monster even after what it did to you. You really are a naive human, Dash.","TWN":"你都被那樣對待還試圖理解那個怪物，真是個天真的人類。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"헤헤.","JPN":"へへ。","ENG":"Hehe.","TWN":"嘿嘿。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"어찌 됐든, 진실은 알 수 없겠죠.","JPN":"とにかく、真実を知るすべはありません。","ENG":"In any case, we'll never know the truth.","TWN":"不論如何，真相已經無從得知了。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};